hooks.command:
python3 -c "import json,shlex,sys
data=json.load(sys.stdin)
cmd=data.get('tool_input',{}).get('command','')
try:
    tokens=shlex.split(cmd)
except ValueError:
    tokens=cmd.split()
for i in range(len(tokens)-1):
    if tokens[i]=='git' and tokens[i+1]=='commit':
        for t in tokens[i+2:]:
            if t in ('&&','||',';','|'):
                break
            if t=='--no-verify' or (t.startswith('-') and not t.startswith('--') and 'n' in t[1:]):
                print('Blocked: git commit --no-verify/-n bypasses the pre-commit hook (lint-staged/prettier/eslint). Fix the underlying lint/format failure instead of skipping the hook.',file=sys.stderr)
                sys.exit(2)
"
